from lfx.schema import Data, Message

class EmbedTextComponent(Component):
    display_name = "Embed Queries"
    description = "Converts input queries into vectors."
    icon = "binary"
    name = "EmbedText"
    category = "processing"

    inputs = [
        BoolInput(
            name="enable",
            display_name="Enable",
            input_types=["bool"],
            value=True,
            info="If false, skips embedding entirely."
        ),
        HandleInput(
            name="embedding_model",
            display_name="Embedding Model",
            input_types=["Embeddings"],
            required=True
        ),
        HandleInput(
            name="input_data",
            display_name="Queries",
            required=False,
            input_types=["Message", "list", "str"],
            is_list=True,
            info="Connect multiple wires to batch them together."
        )
    ]

    outputs = [
        Output(display_name="Query Vectors", name="vector_payload", method="embed_text")
    ]

    def embed_text(self) -> Data:
        # --- THE VALVE ---
        if not self.enable:
            #print("[EmbedTextComponent] Skipping: Node disabled via valve.")
            return Data(data={"vectors": []})
            
        inputs = self.input_data
        
        # Fallback safety for missing inputs
        if inputs is None:
            #print("[EmbedTextComponent] Skipping: Input is None.")
            return Data(data={"vectors": []})
            
        # --- NORMALIZE & FLATTEN INPUTS ---
        # Langflow's `is_list=True` creates nested lists if fed an array. 
        # We recursively extract all strings to handle any depth.
        texts_to_embed = []
        
        def extract_text(item):
            if isinstance(item, str):
                texts_to_embed.append(item)
            elif isinstance(item, Message):
                texts_to_embed.append(item.text)
            elif isinstance(item, list):
                for sub_item in item:
                    extract_text(sub_item) # Recurse into nested lists
            elif item is not None:
                # Catch-all for Data objects or other types
                texts_to_embed.append(item.text if hasattr(item, 'text') else str(item))

        extract_text(inputs)

        # Filter out empty or whitespace-only strings
        texts_to_embed = [t for t in texts_to_embed if t and str(t).strip()]

        # This catches the dummy [Message(text="")] from the parser
        if not texts_to_embed:
            #print("[EmbedTextComponent] Skipping: Input resolved to empty string(s).")
            return Data(data={"vectors": []})
            
        # Optimize: Use batch embedding if multiple texts, otherwise single query
        try:
            if len(texts_to_embed) > 1:
                vectors = self.embedding_model.embed_documents(texts_to_embed)
            else:
                vectors = [self.embedding_model.embed_query(texts_to_embed[0])]
        except Exception as e:
            #print(f"[EmbedTextComponent] Embedding failed: {e}")
            return Data(data={"vectors": []})
            
        return Data(data={"vectors": vectors})

