                "db_type": "lancedb",
                "db_path": "/data"
            }
        }

        incoming = self.rag_configs_dict if isinstance(self.rag_configs_dict, dict) else {}

        merged = {}
        for task_title, default_config in defaults.items():
            task_config = default_config.copy()
            
            if task_title in incoming and isinstance(incoming[task_title], dict):
                task_config.update(incoming[task_title])
                
            merged[task_title] = task_config
            
        return merged

    def get_user_query_config(self) -> dict:
        return self._get_merged_configs().get("user_query", {})

    def get_user_context_config(self) -> dict:
        return self._get_merged_configs().get("user_context", {})
